// Preview overlay
.r-overlay-preview .r-overlay-content iframe {
	width: 100%;
	height: 100%;
	max-width: 100%;
	max-height: 100%;
	border: 0;

	opacity: 0;
	visibility: hidden;
	transition: all 0.3s ease;
}

.r-overlay-preview[data-state='loaded'] iframe {
	opacity: 1;
	visibility: visible;
}

.r-overlay-preview .r-overlay-content img,
.r-overlay-preview .r-overlay-content video {
	position: absolute;
	max-width: 100%;
	max-height: 100%;
	width: 100%;
	height: 100%;
	margin: 0;
	object-fit: scale-down;
}

.r-overlay-preview[data-preview-fit='none'] img,
.r-overlay-preview[data-preview-fit='none'] video {
	object-fit: none;
}

.r-overlay-preview[data-preview-fit='scale-down'] img,
.r-overlay-preview[data-preview-fit='scale-down'] video {
	object-fit: scale-down;
}

.r-overlay-preview[data-preview-fit='contain'] img,
.r-overlay-preview[data-preview-fit='contain'] video {
	object-fit: contain;
}

.r-overlay-preview[data-preview-fit='cover'] img,
.r-overlay-preview[data-preview-fit='cover'] video {
	object-fit: cover;
}

.r-overlay-preview[data-state='loaded'] .r-overlay-content-inner {
	position: absolute;
	z-index: -1;
	left: 0;
	top: 45%;
	width: 100%;
	text-align: center;
	letter-spacing: normal;
}
.r-overlay-preview .r-overlay-error {
	font-size: 18px;
	color: orange;
}

.r-overlay-preview .x-frame-error {
	opacity: 0;
	transition: opacity 0.3s ease 0.3s;
}
.r-overlay-preview[data-state='loaded'] .x-frame-error {
	opacity: 1;
}

.r-overlay-preview[data-state='loading'] .r-overlay-spinner {
	opacity: 0.6;
	visibility: visible;
}

// Help overlay
.r-overlay-help .r-overlay-content {
	overflow: auto;
}

.r-overlay-help-content {
	max-width: 560px;
	padding: 20px 0;
	margin: auto;
	text-align: center;
	letter-spacing: normal;
}

.r-overlay-help-content .title {
	font-size: 20px;
	margin-top: 0;
}

/* Specificity battle with reveal.js theme table styles */
.r-overlay-help .r-overlay-help-content table {
	border: 1px solid #fff;
	border-collapse: collapse;
	font-size: 16px;
	text-align: left;
}

.r-overlay-help .r-overlay-help-content table th,
.r-overlay-help .r-overlay-help-content table td {
	width: 240px;
	padding: 14px;
	border: 1px solid #fff;
	vertical-align: middle;
}

.r-overlay-help .r-overlay-help-content table th {
	padding-top: 20px;
	padding-bottom: 20px;
}

/*********************************************
 * PLAYBACK COMPONENT
 *********************************************/

.reveal .playback {
	position: absolute;
	left: 15px;
	bottom: 20px;
	z-index: 30;
	cursor: pointer;
	transition: all 400ms ease;
	-webkit-tap-highlight-color: rgba(0, 0, 0, 0);
}

.reveal.overview .playback {
	opacity: 0;
	visibility: hidden;
}

/*********************************************
 * CODE HIGHLGIHTING
 *********************************************/

.reveal .hljs {
	min-height: 100%;
}

.reveal .hljs table {
	margin: initial;
}

.reveal .hljs-ln-code,
.reveal .hljs-ln-numbers {
	padding: 0;
	border: 0;
}

.reveal .hljs-ln-numbers {
	opacity: 0.6;
	padding-right: 0.75em;
	text-align: right;
	vertical-align: top;
}

.reveal .hljs.has-highlights tr:not(.highlight-line) {
	opacity: 0.4;
}

.reveal .hljs.has-highlights.fragment {
	transition: all 0.2s ease;
}

.reveal .hljs:not(:first-child).fragment {
	position: absolute;
	top: 0;
	left: 0;
	width: 100%;
	box-sizing: border-box;
}

.reveal pre[data-auto-animate-target] {
	overflow: hidden;
}
.reveal pre[data-auto-animate-target] code {
	height: 100%;
}

/*********************************************
 * ROLLING LINKS
 *********************************************/

.reveal .roll {
	display: inline-block;
	line-height: 1.2;
	overflow: hidden;

	vertical-align: top;
	perspective: 400px;
	perspective-origin: 50% 50%;
}
.reveal .roll:hover {
	background: none;
	text-shadow: none;
}
.reveal .roll span {
	display: block;
	position: relative;
	padding: 0 2px;

	pointer-events: none;
	transition: all 400ms ease;
	transform-origin: 50% 0%;
	transform-style: preserve-3d;
	backface-visibility: hidden;
}
.reveal .roll:hover span {
	background: rgba(0, 0, 0, 0.5);
	transform: translate3d(0px, 0px, -45px) rotateX(90deg);
}
.reveal .roll span:after {
	content: attr(data-title);

	display: block;
	position: absolute;
	left: 0;
	top: 0;
	padding: 0 2px;
	backface-visibility: hidden;
	transform-origin: 50% 0%;
	transform: translate3d(0px, 110%, 0px) rotateX(-90deg);
}

/*********************************************
 * SPEAKER NOTES
 *********************************************/

$notesWidthPercent: 25%;

// Hide on-page notes
.reveal aside.notes {
	display: none;
}

// An interface element that can optionally be used to show the
// speaker notes to all viewers, on top of the presentation
.reveal .speaker-notes {
	display: none;
	position: absolute;
	width: math.div($notesWidthPercent, (1 - math.div($notesWidthPercent, 100))) * 1%;
	height: 100%;
	top: 0;
	left: 100%;
	padding: 14px 18px 14px 18px;
	z-index: 1;
	font-size: 18px;
	line-height: 1.4;
	border: 1px solid rgba(0, 0, 0, 0.05);
	color: #222;
	background-color: #f5f5f5;
	overflow: auto;
	box-sizing: border-box;
	text-align: left;
	font-family: Helvetica, sans-serif;
	-webkit-overflow-scrolling: touch;

	.notes-placeholder {
		color: #ccc;
		font-style: italic;
	}

	&:focus {
		outline: none;
	}

	&:before {
		content: 'Speaker notes';
		display: block;
		margin-bottom: 10px;
		opacity: 0.5;
	}
}

.reveal.show-notes {
	max-width: 100% - $notesWidthPercent;
	overflow: visible;
}

.reveal.show-notes .speaker-notes {
	display: block;
}

@media screen and (min-width: 1600px) {
	.reveal .speaker-notes {
		font-size: 20px;
	}
}

@media screen and (max-width: 1024px) {
	.reveal.show-notes {
		border-left: 0;
		max-width: none;
		max-height: 70%;
		max-height: 70vh;
		overflow: visible;
	}

	.reveal.show-notes .speaker-notes {
		top: 100%;
		left: 0;
		width: 100%;
		height: 30vh;
		border: 0;
	}
}

@media screen and (max-width: 600px) {
	.reveal.show-notes {
		max-height: 60%;
		max-height: 60vh;
	}

	.reveal.show-notes .speaker-notes {
		top: 100%;
		height: 40vh;
	}

	.reveal .speaker-notes {
		font-size: 14px;
	}
}

/*********************************************
 * JUMP-TO-SLIDE COMPONENT
 *********************************************/

.reveal .jump-to-slide {
	position: absolute;
	top: 15px;
	left: 15px;
	z-index: 30;
	font-size: 32px;
	-webkit-tap-highlight-color: rgba(0, 0, 0, 0);
}

.reveal .jump-to-slide-input {
	background: transparent;
	padding: 8px;
	font-size: inherit;
	color: currentColor;
	border: 0;
}
.reveal .jump-to-slide-input::placeholder {
	color: currentColor;
	opacity: 0.5;
}

.reveal.has-dark-background .jump-to-slide-input {
	color: #fff;
}
.reveal.has-light-background .jump-to-slide-input {
	color: #222;
}

.reveal .jump-to-slide-input:focus {
	outline: none;
}

/*********************************************
 * MANUAL MEDIA PLAY BUTTON
 *********************************************/

.reveal .r-overlay-button {
	all: unset;
	position: absolute;
	display: flex;
	align-items: center;
	justify-content: center;
	padding: 10px;
	border-radius: 5px;
	font-size: 0.4em;
	z-index: 30;
	cursor: pointer;
	-webkit-tap-highlight-color: rgba(0, 0, 0, 0);
	-webkit-appearance: none;
	appearance: none;
	color: #fff;
	background: rgba(0, 0, 0, 0.7);

	&:hover {
		background: rgba(0, 0, 0, 0.9);
	}
}

.reveal.has-light-background .r-overlay-button {
	color: #222;
	background: rgba(255, 255, 255, 0.7);

	&:hover {
		background: rgba(255, 255, 255, 0.9);
	}
}

.reveal .r-media-play-button {
	left: 15px;
	bottom: 20px;
}

/*********************************************
 * ZOOM PLUGIN
 *********************************************/

.zoomed .reveal *,
.zoomed .reveal *:before,
.zoomed .reveal *:after {
	backface-visibility: visible !important;
}

.zoomed .reveal .progress,
.zoomed .reveal .controls {
	opacity: 0;
}

.zoomed .reveal .roll span {
	background: none;
}

.zoomed .reveal .roll span:after {
	visibility: hidden;
}

/*********************************************
 * SCROLL VIEW
 *********************************************/
.reveal-viewport.loading-scroll-mode {
	visibility: hidden;
}

.reveal-viewport.reveal-scroll {
	& {
		margin: 0 auto;
		overflow: auto;
		overflow-x: hidden;
		overflow-y: auto;
		z-index: 1;

		--r-scrollbar-width: 7px;
		--r-scrollbar-trigger-size: 5px;
		--r-controls-spacing: 8px;
	}

	@media screen and (max-width: 500px) {
		--r-scrollbar-width: 3px;
		--r-scrollbar-trigger-size: 3px;
	}

	.controls,
	.progress,
	.playback,
	.backgrounds,
	.slide-number,
	.speaker-notes {
		display: none !important;
	}

	.r-overlay,
	.pause-overlay,
	.r-media-play-button {
		position: fixed;
	}

	.reveal {
		overflow: visible;
		touch-action: manipulation;
	}

	.slides {
		position: static;
		pointer-events: initial;

		left: auto;
		top: auto;
		width: 100% !important;
		margin: 0;
		padding: 0;

		overflow: visible;
		display: block;

		perspective: none;
		perspective-origin: 50% 50%;
	}

	.scroll-page {
		position: relative;
		width: 100%;
		height: calc(var(--page-height) + var(--page-scroll-padding));
		z-index: 1;
		overflow: visible;
	}

	.scroll-page-sticky {
		position: sticky;
		height: var(--page-height);
		top: 0px;
	}

	.scroll-page-content {
		position: absolute;
		top: 0;
		left: 0;
		width: 100%;
		height: 100%;
		overflow: hidden;
	}

	.scroll-page section {
		visibility: visible !important;
		display: block !important;
		position: absolute !important;
		width: var(--slide-width) !important;
		height: var(--slide-height) !important;
		top: 50% !important;
		left: 50% !important;
		opacity: 1 !important;
		transform: scale(var(--slide-scale)) translate(-50%, -50%) !important;
		transform-style: flat !important;
		transform-origin: 0 0 !important;
	}

	.slide-background {
		display: block !important;
		position: absolute;
		top: 0;
		left: 0;
		width: 100%;
		height: 100%;
		z-index: auto !important;
		visibility: visible;
		opacity: 1;
		touch-action: manipulation;
	}
}

// Chromium
.reveal-viewport.reveal-scroll[data-scrollbar='true']::-webkit-scrollbar,
.reveal-viewport.reveal-scroll[data-scrollbar='auto']::-webkit-scrollbar {
	display: none;
}

// Firefox
.reveal-viewport.reveal-scroll[data-scrollbar='true'],
.reveal-viewport.reveal-scroll[data-scrollbar='auto'] {
	scrollbar-width: none;
}

.reveal.has-dark-background,
.reveal-viewport.has-dark-background {
	--r-overlay-element-bg-color: 240, 240, 240;
	--r-overlay-element-fg-color: 0, 0, 0;
}
.reveal.has-light-background,
.reveal-viewport.has-light-background {
	--r-overlay-element-bg-color: 0, 0, 0;
	--r-overlay-element-fg-color: 240, 240, 240;
}

.reveal-viewport.reveal-scroll .scrollbar {
	position: sticky;
	top: 50%;
	z-index: 20;
	opacity: 0;
	transition: all 0.3s ease;

	&.visible,
	&:hover {
		opacity: 1;
	}

	.scrollbar-inner {
		position: absolute;
		width: var(--r-scrollbar-width);
		height: calc(var(--viewport-height) - var(--r-controls-spacing) * 2);
		right: var(--r-controls-spacing);
		top: 0;
		transform: translateY(-50%);
		border-radius: var(--r-scrollbar-width);
		z-index: 10;
	}

	.scrollbar-playhead {
		position: absolute;
		width: var(--r-scrollbar-width);
		height: var(--r-scrollbar-width);
		top: 0;
		left: 0;
		border-radius: var(--r-scrollbar-width);
		background-color: rgba(var(--r-overlay-element-bg-color), 1);
		z-index: 11;
		transition: background-color 0.2s ease;
	}

	.scrollbar-slide {
		position: absolute;
		width: 100%;
		background-color: rgba(var(--r-overlay-element-bg-color), 0.2);
		box-shadow: 0 0 0px 1px rgba(var(--r-overlay-element-fg-color), 0.1);
		border-radius: var(--r-scrollbar-width);
		transition: background-color 0.2s ease;
	}

	// Hit area
	.scrollbar-slide:after {
		content: '';
		position: absolute;
		width: 200%;
		height: 100%;
		top: 0;
		left: -50%;
		background: rgba(0, 0, 0, 0);
		z-index: -1;
	}

	.scrollbar-slide:hover,
	.scrollbar-slide.active {
		background-color: rgba(var(--r-overlay-element-bg-color), 0.4);
	}

	.scrollbar-trigger {
		position: absolute;
		width: 100%;
		transition: background-color 0.2s ease;
	}

	.scrollbar-slide.active.has-triggers {
		background-color: rgba(var(--r-overlay-element-bg-color), 0.4);
		z-index: 10;
	}

	.scrollbar-slide.active .scrollbar-trigger:after {
		content: '';
		position: absolute;
		width: var(--r-scrollbar-trigger-size);
		height: var(--r-scrollbar-trigger-size);
		border-radius: 20px;
		top: 50%;
		left: 50%;
		transform: translate(-50%, -50%);
		background-color: rgba(var(--r-overlay-element-bg-color), 1);
		transition:
			transform 0.2s ease,
			opacity 0.2s ease;
		opacity: 0.4;
	}

	.scrollbar-slide.active .scrollbar-trigger.active:after,
	.scrollbar-slide.active .scrollbar-trigger.active ~ .scrollbar-trigger:after {
		opacity: 1;
	}

	.scrollbar-slide.active .scrollbar-trigger ~ .scrollbar-trigger.active:after {
		transform: translate(calc(var(--r-scrollbar-width) * -2), 0);
		background-color: rgba(var(--r-overlay-element-bg-color), 1);
	}
}

/*********************************************
 * PRINT STYLES
 *********************************************/

@include meta.load-css('print/pdf.scss');
@include meta.load-css('print/paper.scss');

