		if( this.pendingScrollRaf ) return;

		this.pendingScrollRaf = requestAnimationFrame( () => {
			this.pendingScrollRaf = 0;
			this.syncScrollPosition();
			this.storeScrollPosition();
		} );

	}

	get viewportElement() {

		return this.Reveal.getViewportElement();

	}

